aaam_product_catalog_product_preview_hint_description__content__text = TextObject(bs_BA="Dodirnite „Home“\nkako biste sada\ndoživjeli temu.", cs_CZ="Klepněte na\ntlačítko „Home“ a\nzjistěte více o\ntématu.", da_DK="Tryk på \"Hjem\" for\nnu at opleve\ntemaet.", de_DE="Tippe auf \"Home\",\num das Theme jetzt\nzu erleben.", el_GR="Πιέστε σύντομα στο\n\"Home\", για να\nβιώσετε τώρα το\nθέμα.", en_GB="Tap \"Home\" to\nexperience the\ntheme now.", es_ES="Pulse en \"Inicio\"\npara experimentar\nla temática ahora.", fi_FI="Voit nyt kokea\nteeman painamalla\n\"Home\".", fr_FR="Appuyez\nbrièvement sur\n«Accueil» pour\nprofiter désormais\ndu thème.", hr_HR="Dodirnite \"Home\"\nkako biste sada\ndoživjeli temu.", hu_HU="Érintsd meg a\n„Home”-ot, hogy\nmegismerhesd a\nTémát.", it_IT="Toccare \"Home\" per\nprovare subito il\ntema.", nl_NL="Tik op \"Home\" om\nhet thema nu te\nweten te komen.", no_NO="Trykk på \"Hjem\" for\nå se temaet nå.", pl_PL="Dotknij „Home”,\naby zobaczyć\ntematykę teraz.", pt_PT="Clicar em \"Home\"\npara vivenciar\nagora o tema.", ro_RO="Apăsaţi pe \"Home\",\npentru a\nexperimenta acum\ntema.", ru_RU="Нажмите на\n«Главная», чтобы\nознакомиться с\nтемой.", sk_SK="Krátko stlačte\n\"Home\", aby ste\nteraz zažili Tému.", sl_SI="Pritisnite \"Začetni\nzaslon\", da izkusite\ntemo.", sr_RS="Dodirnite na\n„Home“ da biste\nsada doživeli temu.", sv_SE="Tryck på \"Home\"\nför att uppleva\ntemat direkt.", tr_TR="Temayı şimdi\ndeneyimlemek için\n\"Ana Sayfa\" üzerine\ndokun.", uk_UA="Натисніть на\n«Головна\nсторінка»\nщоб ознайомитися\nз темою зараз.")
aaam_product_catalog_product_preview_hint_description_interactive__content__text = TextObject(bs_BA="Pregled teme je\nutemeljen na\ndogađajima sa\nvremenskim\nupravljanjem.", cs_CZ="Náhled tématu je\nzaložen na časově\nřízených\nudálostech.", da_DK="Forhåndsvisning af\ntema er baseret på\ntidsstyrede\nhændelser.", de_DE="Die Vorschau des\nThemes basiert auf\nzeitgesteuerten\nEreignissen.", el_GR="Η προεπισκόπηση\nτου θέματος\nβασίζεται σε\nχρονικά ελεγχόμενα\nσυμβάντα.", en_GB="The preview of the\ntheme depends on\ntime-based events.", es_ES="La vista previa de la\ntemática depende\nde varios factores.", fi_FI="Teeman esikatselu\nperustuu\naikaohjattuihin\ntapahtumiin.", fr_FR="L'aperçu du thème\nest basé sur des\névénements\ntemporels.", hr_HR="Pregled teme\nbaziran je na\nvremenski\nuvjetovanim\ndogađajima.", hu_HU="A Téma előnézete\nidővezérelt\neseményeken\nalapul.", it_IT="L'anteprima del\ntema si basa su\neventi in base al\ntempo.", nl_NL="Het voorbeeld van\nhet thema is\ngebaseerd op\ntijdgestuurde\ngebeurtenissen.", no_NO="Forhåndsvisningen\nav temaet er basert\npå tidsstyrte\nhendelser.", pl_PL="Podgląd tematu\nopiera się na\nzdarzeniach\nsterowanych\nczasowo.", pt_PT="A pré-visualização\ndos temas tem por\nbase as ocorrências\ngeridas pelo\ntempo.", ro_RO="Previzualizarea\ntemei se bazează\npe evenimente\ncomandate în\nfuncţie de timp.", ru_RU="Предв. просмотр\nтемы основан на\nсобытиях,\nуправляемых по\nвремени.", sk_SK="Ukážka Téma je\nzaložená na časovo\nriadených\nudalostiach.", sl_SI="Predogled teme\ntemelji na časovno\nnadzorovanih\ndogodkih.", sr_RS="Pregled teme je\nzasnovan na\ndogađajima sa\nvremenskim\nupravljanjem.", sv_SE="Förhandsvisningen\nav temat är\nbaserad på\ntidsreglerade\nhändelser.", tr_TR="Temanın\nönizlemesi zaman\nkontrollü olaylara\ndayanmaktadır.", uk_UA="Попередній\nперегляд теми\nзаснований на\nподіях, керованих\nза часом.")
