reasonbackend_no_active_license__error_message_text = TextObject(bs_BA="Došlo je do greške. Licenca je istekla.", cs_CZ="Vyskytla se chyba. Licence vypršela.", da_DK="Fejl opstået. Licens udløbet.", de_DE="Es ist ein Fehler aufgetreten. Die Lizenz ist abgelaufen.", el_GR="Προέκυψε σφάλμα. Η ισχύς της άδειας έληξε.", en_GB="An error has occurred. The licence has expired.", es_ES="Se ha producido un error. La licencia ha caducado.", fi_FI="Tapahtui virhe. Lisenssi on vanhentunut", fr_FR="Une erreur s'est produite. La licence a expiré.", hr_HR="Pojavila se greška. Licenca je istekla.", hu_HU="Hiba lépett fel. A licenc lejárt.", it_IT="Si è verificato un errore. La licenza è scaduta.", nl_NL="Er is een fout opgetreden. De licentie is verlopen.", no_NO="Det har oppstått en feil. Lisensen er utløpt.", pl_PL="Wystąpił błąd. Licencja straciła ważność.", pt_PT="Ocorreu um erro. A licença expirou.", ro_RO="A survenit o eroare. Licenţa a expirat.", ru_RU="Произошла ошибка. Срок действия лицензии истек.", sk_SK="Vyskytla sa chyba. Platnosť licencie uplynula.", sl_SI="Prišlo je do napake. Licenca je potekla.", sr_RS="Došlo je do greške. Licenca je istekla.", sv_SE="Ett fel har uppstått. Licensen har löpt ut.", tr_TR="Bir hata oluştu. Lisans süresi doldu.", uk_UA="Сталася помилка. Строк дії ліцензії закінчився.")
