reasonbackend_switched_off__error_message_text = TextObject(bs_BA="Došlo je do greške. Aktivirajte ovu uslugu na myAudi portalu ili u myAudi aplikaciji. Aplikaciju\nmožete i dalje koristiti u vanmrežnom režimu.", cs_CZ="Došlo k chybě. Aktivujte si tuto službu na portálu myAudi nebo v aplikaci myAudi. Aplikaci\nmůžete stále používat v režimu offline.", da_DK="Fejl opstået. Aktiver denne tjeneste på myAudi-portalen eller i myAudi-appen. Du kan fortsat\nanvende appen i offlineindstillingen.", de_DE="Es ist ein Fehler aufgetreten. Bitte aktiviere diesen Dienst im myAudi Portal oder in der\nmyAudi App. Du kannst die App weiterhin im Offline-Modus nutzen.", el_GR="Παρουσιάστηκε σφάλμα. Ενεργοποιήστε αυτήν την υπηρεσία στη διαδικτυακή πύλη myAudi ή\nστην εφαρμογή myAudi. Μπορείτε να συνεχίσετε να χρησιμοποιείτε την εφαρμογή στη\nλειτουργία offline.", en_GB="An error has occurred. Please activate this service in the myAudi portal or the myAudi app.\nYou can still use the app in offline mode.", es_ES="Se ha producido un error. Active este servicio en el portal myAudi o en la App myAudi. Puede\nseguir utilizando la App en modo offline.", fi_FI="Tapahtui virhe. Aktivoi tämä palvelu myAudi-portaalin tai myAudi-sovelluksen kautta. Voit\nedelleen käyttää sovellusta offline-tilassa.", fr_FR="Une erreur s'est produite. Veuillez activer ce service sur le portail myAudi ou dans\nl'application myAudi. Vous pouvez continuer à utiliser l'application en mode hors ligne.", hr_HR="Nastupila je greška. Aktivirajte ovu uslugu na myAudi portalu ili u myAudi aplikaciji. Aplikaciju\nmožete nastaviti koristiti u offline modusu.", hu_HU="Hiba lépett fel. Aktiváld ezt a szolgáltatást a myAudi portálon vagy a myAudi alkalmazásban.\nOffline módban továbbra is használhatod az alkalmazást.", it_IT="Si è verificato un errore. Attivare questo servizio sul portale myAudi o nell'app myAudi. È\npossibile continuare a utilizzare l'app in modalità offline.", nl_NL="Er is een fout opgetreden. Activeer deze dienst in het myAudi portaal of in de myAudi app. Je\nkunt de app nog steeds gebruiken in de offlinemodus.", no_NO="Det har oppstått en feil. Aktiver tjenesten i myAudi-portalen eller myAudi-appen. Du kan\nfortsatt bruke appen i offline-modus.", pl_PL="Pojawił się błąd. Proszę włączyć tę usługę na portalu myAudi lub w aplikacji myAudi. Możesz\ndalej korzystać z aplikacji w trybie offline.", pt_PT="Ocorreu um erro. Por favor, ative esta serviço no Portal myAudi ou na myAudi app. Podes\ncontinuar a utilizar a aplicação no modo offline.", ro_RO="A survenit o eroare. Activaţi acest serviciu în portalul myAudi sau în aplicaţia myAudi. Puteţi\nutiliza aplicaţia în continuare, în modul offline.", ru_RU="Произошла ошибка. Активируйте этот сервис на портале myAudi или в приложении\nmyAudi. Вы по-прежнему можете использовать приложение в автономном режиме.", sk_SK="Vyskytla sa chyba. Prosím, aktivujte si túto službu na portáli myAudi alebo v aplikácii myAudi.\nAplikáciu môžete používať naďalej v režime offline.", sl_SI="Prišlo je do napake. Storitev aktivirajte na portalu myAudi ali v aplikaciji myAudi. Aplikacijo\nlahko še naprej uporabljate v načinu brez povezave.", sr_RS="Došlo je do greške. Aktivirajte ovu uslugu na portalu myAudi ili u aplikaciji myAudi. Aplikaciju\nmožete da koristite i dalje u vanmrežnom režimu.", sv_SE="Ett fel har uppstått. Aktivera denna tjänst i myAudi-portalen eller i myAudi-appen. Du kan\nfortfarande använda appen i offline-läget.", tr_TR="Bir hata oluştu. Lütfen bu hizmeti myAudi portalında veya myAudi uygulamasında etkinleştir.\nUygulamayı çevrimdışı modda kullanmaya devam edebilirsin.", uk_UA="Сталася помилка. Активуйте цю службу на порталі myAudi або в програмі myAudi. Ви все\nще можете користуватися програмою в автономному режимі.")
reasonbackend_switched_off__titleline_title = TextObject(bs_BA="Tematski svijet: Napomena", cs_CZ="Témata: Poznámka", da_DK="Temaunivers: Bemærk", de_DE="Themenwelt: Hinweis", el_GR="Θεματικός κόσμος: Υπόδειξη", en_GB="Themes: information", es_ES="Configuración temática: Nota", fi_FI="Teema-toiminto: ohje", fr_FR="Univers thématiques: nota", hr_HR="Svijet tema: napomena", hu_HU="Témák: megjegyzés", it_IT="Temi: avvertenza", nl_NL="Themawereld: aanwijzing", no_NO="Temaer: Informasjon", pl_PL="Tematytka: informacja", pt_PT="Temas globais: Indicação", ro_RO="Lume tematică: indicaţie", ru_RU="Темы: примечание", sk_SK="Výber tém: upozornenie", sl_SI="Tematski svet: napotek", sr_RS="Tematski svet: Napomena", sv_SE="Teman: Anvisning", tr_TR="Tema dünyası: Not", uk_UA="Теми: вказівки")
reasonconnectivity_blocked__confirm_button__label = TextObject(bs_BA="OK", cs_CZ="OK", da_DK="OK", de_DE="OK", el_GR="OK", en_GB="OK", es_ES="OK", fi_FI="OK", fr_FR="OK", hr_HR="OK", hu_HU="OK", it_IT="OK", nl_NL="OK", no_NO="OK", pl_PL="OK", pt_PT="OK", ro_RO="OK", ru_RU="OK", sk_SK="OK", sl_SI="OK", sr_RS="OK", sv_SE="OK", tr_TR="OK", uk_UA="OK")
reasonconnectivity_blocked__error_message__text = TextObject(bs_BA="Došlo je do greške. Podatkovna veza trenutno nije moguća. Pokušajte ponovo kasnije.\nAplikaciju možete i dalje koristiti u vanmrežnom režimu.", cs_CZ="Došlo k chybě. V současné době není možné datové připojení. Zkuste to znovu později.\nAplikaci můžete stále používat v režimu offline.", da_DK="Fejl opstået. Ingen dataforbindelse mulig p.t. Forsøg igen senere. Du kan stadig anvende\nappen i offlineindstillingen.", de_DE="Es ist ein Fehler aufgetreten. Zurzeit ist keine Datenverbindung möglich. Bitte versuche es\nspäter erneut. Du kannst die App weiterhin im Offline-Modus nutzen.", el_GR="Παρουσιάστηκε σφάλμα. Προς το παρόν δεν είναι εφικτή η δημιουργία σύνδεσης δεδομένων.\nΠροπαθήστε πάλι αργότερα. Μπορείτε να συνεχίσετε να χρησιμοποιείτε την εφαρμογή στη\nλειτουργία offline.", en_GB="An error has occurred. A data connection is currently not possible. Please try again later. You\ncan still use the app in offline mode.", es_ES="Se ha producido un error. Actualmente la conexión de datos no es posible. Inténtelo de nuevo\nmás tarde. Puede seguir utilizando la App en modo offline.", fi_FI="Tapahtui virhe. Datayhteys ei ole tällä hetkellä mahdollinen. Yritä myöhemmin uudelleen.\nVoit edelleen käyttää sovellusta offline-tilassa.", fr_FR="Une erreur s'est produite. Aucune connexion de données n'est possible actuellement. Veuillez\nréessayer ultérieurement. Vous pouvez continuer à utiliser l'application en mode hors ligne.", hr_HR="Nastupila je greška. Trenutačno nije moguća veza za prijenos podataka. Pokušajte ponovno\nkasnije. Možete nastaviti koristiti aplikaciju u offline modusu.", hu_HU="Hiba lépett fel. Jelenleg nem lehetséges adatkapcsolat. Kérünk, próbáld újra később. Offline\nmódban továbbra is használhatod az alkalmazást.", it_IT="Si è verificato un errore. Il collegamento dati non è possibile al momento. Si prega di\nriprovare più tardi. È possibile continuare a utilizzare l'app in modalità offline.", nl_NL="Er is een fout opgetreden. Er is momenteel geen dataverbinding mogelijk. Probeer het later\nopnieuw. Je kunt de app nog steeds gebruiken in de offlinemodus.", no_NO="Det har oppstått en feil. Ingen dataforbindelse er mulig for øyeblikket. Prøv igjen senere. Du\nkan fortsatt bruke appen i offline-modus.", pl_PL="Wystąpił błąd. Obecnie połączenie do transmisji danych jest niemożliwe. Spróbuj ponownie\npóźniej. Możesz nadal korzystać z aplikacji w trybie offline.", pt_PT="Ocorreu um erro. De momento não é possível uma ligação de dados. Por favor, volta a tentar\nmais tarde. Podes continuar a utilizar a aplicação no modo offline.", ro_RO="A survenit o eroare. Momentan nu este posibilă o conexiune de date. Reîncercaţi mai târziu.\nPuteţi utiliza aplicaţia în continuare, în modul offline.", ru_RU="Произошла ошибка. В настоящее время соединение для передачи данных невозможно.\nПожалуйста, повторите попытку позже. Вы по-прежнему можете использовать\nприложение в автономном режиме.", sk_SK="Vyskytla sa chyba. Momentálne nie je možné žiadne dátové pripojenie. Prosím, pokúste sa o\nto znovu neskôr. Aplikáciu môžete používať naďalej v režime offline.", sl_SI="Prišlo je do napake. Podatkovna povezava trenutno ni mogoča. Poskusite znova pozneje.\nAplikacijo lahko še naprej uporabljate v načinu brez povezave.", sr_RS="Došlo je do greške. Trenutno nije moguća veza za prenos podataka. Pokušajte ponovo kasnije.\nAplikaciju možete i dalje da koristite u vanmrežnom režimu.", sv_SE="Ett fel har uppstått. Det går för närvarande inte att upprätta en dataanslutning. Försök igen\nsenare. Du kan fortfarande använda appen i offline-läget.", tr_TR="Bir hata oluştu. Şu anda veri bağlantısı mümkün değildir. Lütfen daha sonra tekrar dene.\nUygulamayı çevrimdışı modda kullanmaya devam edebilirsin.", uk_UA="Сталася помилка. Наразі підключення для передачі даних неможливе. Будь ласка,\nспробуйте пізніше. Ви все ще можете використовувати програму в офлайн-режимі.")
reasonconnectivity_blocked__titleline__title = TextObject(bs_BA="Tematski svijet: Napomena", cs_CZ="Témata: Poznámka", da_DK="Temaunivers: Bemærk", de_DE="Themenwelt: Hinweis", el_GR="Θεματικός κόσμος: Υπόδειξη", en_GB="Themes: information", es_ES="Configuración temática: Nota", fi_FI="Teema-toiminto: ohje", fr_FR="Univers thématiques: nota", hr_HR="Svijet tema: napomena", hu_HU="Témák: megjegyzés", it_IT="Temi: avvertenza", nl_NL="Themawereld: aanwijzing", no_NO="Temaer: Informasjon", pl_PL="Tematytka: informacja", pt_PT="Temas globais: Indicação", ro_RO="Lume tematică: indicaţie", ru_RU="Темы: примечание", sk_SK="Výber tém: upozornenie", sl_SI="Tematski svet: napotek", sr_RS="Tematski svet: Napomena", sv_SE="Teman: Anvisning", tr_TR="Tema dünyası: Not", uk_UA="Теми: вказівки")
